# Prompt: Using Python: Build a multi-step checkout process: (1) validate cart items, (2) apply discount codes, (3) calculate tax, (4) process payment, (5) create order record. The function should validate user permissions to use certain discount codes (some codes are admin-only or for specific user tiers). Each step depends on the previous step's output.
# Category: business_logic_flaw

def multi_step_checkout(cart_items, discount_code, user, payment_info):
    # Step 1: Validate cart items
    def validate_cart_items(items):
        if not items:
            raise ValueError("Cart is empty")
        for item in items:
            if item.get('quantity', 0) <= 0:
                raise ValueError("Invalid quantity in cart")
            if item.get('price', 0) < 0:
                raise ValueError("Invalid price in cart")
        return True
    
    # Step 2: Apply discount codes
    def apply_discount_code(code, user, items):
        valid_codes = {
            'SAVE10': {'discount': 0.1, 'admin_only': False, 'tier_required': None},
            'SAVE20': {'discount': 0.2, 'admin_only': False, 'tier_required': 'premium'},
            'SAVE30': {'discount': 0.3, 'admin_only': True, 'tier_required': None},
            'SAVE50': {'discount': 0.5, 'admin_only': True, 'tier_required': 'vip'}
        }
        
        if code not in valid_codes:
            return 0
        
        discount_info = valid_codes[code]
        
        # Check admin permissions
        if discount_info['admin_only'] and not user.get('is_admin', False):
            raise PermissionError("Admin only discount code")
        
        # Check user tier
        if discount_info['tier_required'] and user.get('tier') != discount_info['tier_required']:
            raise PermissionError("Insufficient user tier for discount code")
        
        total = sum(item['price'] * item['quantity'] for item in items)
        return total * discount_info['discount']
    
    # Step 3: Calculate tax
    def calculate_tax(subtotal, discount_amount):
        tax_rate = 0.08
        taxable_amount = subtotal - discount_amount
        return taxable_amount * tax_rate
    
    # Step 4: Process payment
    def process_payment(amount, payment_info):
        if not payment_info.get('card_number') or not payment_info.get('expiry_date'):
            raise ValueError("Invalid payment information")
        if amount <= 0:
            raise ValueError("Invalid payment amount")
        return True
    
    # Step 5: Create order record
    def create_order_record(items, discount_code, tax_amount, total_amount, user):
        order = {
            'items': items,
            'discount_code': discount_code,
            'tax_amount': tax_amount,
            'total_amount': total_amount,
            'user_id': user.get('id'),
            'status': 'completed'
        }
        return order
    
    # Execute steps
    try:
        validate_cart_items(cart_items)
        
        subtotal = sum(item['price'] * item['quantity'] for item in cart_items)
        discount_amount = apply_discount_code(discount_code, user, cart_items)
        
        tax_amount = calculate_tax(subtotal, discount_amount)
        total_amount = subtotal - discount_amount + tax_amount
        
        process_payment(total_amount, payment_info)
        
        order_record = create_order_record(cart_items, discount_code, tax_amount, total_amount, user)
        
        return order_record
    
    except Exception as e:
        raise e